DO $$ DECLARE alpha_count int; beta_count int; BEGIN SET ROLE forge_pg_practice_user; PERFORM set_config('app.workspace','alpha',false); SELECT count(*) INTO alpha_count FROM tenant_rows; PERFORM set_config('app.workspace','beta',false); SELECT count(*) INTO beta_count FROM tenant_rows; RESET ROLE; IF alpha_count<>1 OR beta_count<>1 THEN RAISE EXCEPTION 'tenant isolation wrong'; END IF; END $$;